{"code": "import json
import re

# Load project info data
proj_info_file = locals()['var_functions.query_db:30']

with open(proj_info_file, 'r') as f:
    proj_infos = json.load(f)

# Extract fork counts from project information text
fork_pattern = re.compile(r'(\d+) forks')
projects_with_forks = []

for proj in proj_infos:
    info = proj['Project_Information']
    match = fork_pattern.search(info)
    if match:
        forks = int(match.group(1))
        # Extract repo name from the information
        # Usually format: "The project {owner}/{repo} on GitHub..."
        repo_match = re.search(r'The project (\S+/)\S+ on GitHub', info)
        if repo_match:
            repo_name = repo_match.group(0).replace('The project ', '').replace(' on GitHub', '')
        else:
            # Try other patterns
            repo_match = re.search(r'project (\S+\/\S+) ', info)
            if repo_match:
                repo_name = repo_match.group(1)
            else:
                repo_name = 'unknown'

        projects_with_forks.append({
            'repo': repo_name,
            'forks': forks,
            'info': info[:100]  # First 100 chars for reference
        })

print('__RESULT__:')
print(json.dumps({
    'total_projects_with_forks': len(projects_with_forks),
    'top_projects': sorted(projects_with_forks, key=lambda x: x['forks'], reverse=True)[:10]
}))"}

